import { create } from 'zustand';

const useStore = create((set) => ({
  count: 0,
  inc: () => set((s) => ({ count: s.count + 1 })),
}));

export default function Preview() {
  const { count, inc } = useStore();
  return (
    <div style={{ padding: 24, background: '#000', minHeight: 200, color: '#fff' }}>
      <h3>Count: {count}</h3>
      <button onClick={inc} style={{ padding: '8px 16px', borderRadius: 999, border: '1px solid #fff', background: '#000', color: '#fff', cursor: 'pointer' }}>Increment</button>
    </div>
  );
}

